#include<bits/stdc++.h>
using namespace std;
struct node
{
    long long val,lson,rson;
}a[100010];
long long dis[100010],b[100010],l[100010],fa[100010],sum[100010],siz[100010],root[100010];
long long merge(long long x,long long y)
{
    if(x==0||y==0)
    {
        return x+y;
    }
    if(a[x].val<a[y].val)
    {
        swap(x,y);
    }
    a[x].rson=merge(a[x].rson,y);
    if(dis[a[x].lson]<dis[a[x].rson])
    {
        swap(a[x].lson,a[x].rson);
    }
    dis[x]=dis[a[x].rson]+1;
    return x;
}
int main()
{
    long long n,m,ans=0;
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld%lld%lld",&fa[i],&a[i].val,&l[i]);
        root[i]=i;
        sum[i]=a[i].val;
        siz[i]=1;
    }
    dis[0]=-1;
    for(long long i=n;i>=1;i--)
    {
        while(sum[i]>m)
        {
            sum[i]-=a[root[i]].val;
            siz[i]--;
            root[i]=merge(a[root[i]].lson,a[root[i]].rson);
        }
        ans=max(ans,siz[i]*l[i]);
        root[fa[i]]=merge(root[fa[i]],root[i]);
        sum[fa[i]]+=sum[i];
        siz[fa[i]]+=siz[i];
    }
    printf("%lld",ans);
    return 0;
}
